import { readFileSync, writeFileSync } from "node:fs";
import { resolve } from "node:path";

const rootDir = resolve(import.meta.dirname, "..");
const sqlPath = resolve(rootDir, "sql/sqlite/0001_init.sql");
const outputPath = resolve(rootDir, "src/cloudflare/schema.ts");

const sql = readFileSync(sqlPath, "utf8").trimEnd();

const output = `// This file is generated from sql/sqlite/0001_init.sql by:
//   pnpm run sync:schema
// It is also regenerated automatically by:
//   pnpm typecheck
//   pnpm build
// Do not edit this file directly. Edit sql/sqlite/0001_init.sql instead.

import { cloudflareSqliteSchemaVersion } from "../versions";

export const requiredSchemaVersion = cloudflareSqliteSchemaVersion;

export const schemaMigrations = [
\t{
\t\tversion: cloudflareSqliteSchemaVersion,
\t\tname: "init",
\t\tsql: ${JSON.stringify(sql)},
\t},
] as const;
`;

writeFileSync(outputPath, output);
